"""Layer 5: prior-run memory via langchain-oracledb.

Uses sentence-transformers locally for embeddings (no API call), matching the
embedding model used everywhere else in the project so retrieval is consistent
with the migrated RAG corpus.
"""

import os
from functools import lru_cache

from langchain_oracledb.vectorstores import OracleVS
from sentence_transformers import SentenceTransformer

from data_migration_harness.environment import oracle_pool


class LocalSTEmbeddings:
    """Minimal LangChain-compatible embedding wrapper around sentence-transformers."""

    def __init__(self, model_name: str):
        self._model = SentenceTransformer(model_name)

    def embed_documents(self, texts: list[str]) -> list[list[float]]:
        return [vec.tolist() for vec in self._model.encode(texts, normalize_embeddings=True)]

    def embed_query(self, text: str) -> list[float]:
        return self._model.encode([text], normalize_embeddings=True)[0].tolist()


@lru_cache(maxsize=1)
def _embeddings() -> LocalSTEmbeddings:
    return LocalSTEmbeddings(
        os.environ.get("EMBEDDING_MODEL", "sentence-transformers/all-MiniLM-L6-v2")
    )


@lru_cache(maxsize=1)
def get_run_memory() -> OracleVS:
    """Returns a singleton OracleVS instance backed by the agent_run_memory table.

    Passes the pool directly so OracleVS manages connection checkout internally.
    This avoids a leaked acquired connection on each process start.
    """
    return OracleVS(
        client=oracle_pool(),
        embedding_function=_embeddings(),
        table_name="agent_run_memory",
    )


def record_run_summary(text: str, metadata: dict) -> None:
    """Store a run summary as a vector document for later similarity retrieval.

    Args:
        text: Free-text description of what the agent run did.
        metadata: Arbitrary key/value pairs (e.g. run_id, timestamp, side).

    Returns:
        None
    """
    get_run_memory().add_texts([text], metadatas=[metadata])


def find_similar_runs(query: str, k: int = 3):
    """Return the k most similar prior run summaries for a given query.

    Args:
        query: Natural-language description of the current task.
        k: Number of results to return.

    Returns:
        List of LangChain Document objects with page_content and metadata.
    """
    return get_run_memory().similarity_search(query, k=k)

data_migration_harness/schema_discovery..content:
"""MongoDB schema discovery and migration profile selection."""

from __future__ import annotations

from collections import Counter, defaultdict
from dataclasses import asdict, dataclass, field
from datetime import date, datetime
from typing import Any

from data_migration_harness import source_config


@dataclass
class FieldInfo:
    path: str
    types: dict[str, int]
    examples: list[Any] = field(default_factory=list)
    array: bool = False
    vector_dim: int | None = None
    coverage: float = 0.0


@dataclass
class MigrationProfile:
    mode: str
    document_count: int
    sample_size: int
    source: dict
    fields: list[dict]
    vectors: list[dict]
    strategy: dict
    warnings: list[str]

    def to_dict(self) -> dict:
        return asdict(self)


def _type_name(value: Any) -> str:
    if value is None:
        return "null"
    if isinstance(value, bool):
        return "bool"
    if isinstance(value, int) and not isinstance(value, bool):
        return "int"
    if isinstance(value, float):
        return "float"
    if isinstance(value, str):
        return "string"
    if isinstance(value, datetime | date):
        return "date"
    if isinstance(value, list):
        return "array"
    if isinstance(value, dict):
        return "object"
    return type(value).__name__


def _safe_example(value: Any):
    if isinstance(value, datetime | date):
        return value.isoformat()
    if isinstance(value, list):
        if _is_numeric_vector(value):
            return f"[{len(value)} numeric values]"
        return value[:2]
    if isinstance(value, dict):
        return {k: _safe_example(v) for k, v in list(value.items())[:6]}
    return value


def _is_numeric_vector(value: Any) -> bool:
    return (
        isinstance(value, list)
        and len(value) >= 32
        and all(
            isinstance(v, int | float) and not isinstance(v, bool)
            for v in value[: min(len(value), 256)]
        )
    )


def _walk(value: Any, path: str, seen: dict[str, list[Any]]) -> None:
    if path:
        seen[path].append(value)
    if isinstance(value, dict):
        for k, v in value.items():
            child = f"{path}.{k}" if path else k
            _walk(v, child, seen)
    elif isinstance(value, list):
        arr_path = f"{path}[]" if path else "[]"
        for item in value[:3]:
            seen[arr_path].append(item)
            if isinstance(item, dict):
                for k, v in item.items():
                    _walk(v, f"{arr_path}.{k}", seen)


def assess(sample_size: int = 100) -> MigrationProfile:
    col = source_config.collection()
    count = col.count_documents({})
    docs = list(col.find().limit(sample_size))
    seen: dict[str, list[Any]] = defaultdict(list)
    for doc in docs:
        _walk(doc, "", seen)

    fields: list[dict] = []
    vectors: list[dict] = []
    for path, values in sorted(seen.items()):
        if not path or path == "_id":
            continue
        types = Counter(_type_name(v) for v in values)
        info = {
            "path": path,
            "types": dict(types),
            "examples": [_safe_example(v) for v in values[:2]],
            "coverage": round(len(values) / max(len(docs), 1), 3),
        }
        vector_values = [v for v in values if _is_numeric_vector(v)]
        if vector_values:
            dims = Counter(len(v) for v in vector_values)
            dim, dim_count = dims.most_common(1)[0]
            info["vector_dim"] = dim
            info["vector_coverage"] = round(dim_count / max(len(docs), 1), 3)
            vectors.append({"field": path, "dim": dim, "coverage": info["vector_coverage"]})
        fields.append(info)

    paths = {f["path"] for f in fields}
    rich = all(
        p in paths
        for p in ("name", "category", "price", "reviews[]", "reviews[].rating", "reviews[].text")
    )
    warnings: list[str] = []
    if not vectors:
        warnings.append(
            "No vector-like fields detected. Vector migration will be skipped unless embeddings are generated first."
        )
    if not rich:
        warnings.append(
            "Source does not match the product-review demo shape. The harness will use generic JSON landing and scalar projection."
        )

    mode = "rich_product_reviews" if rich else "generic_json"
    strategy = {
        "landing": "oracle_json_table",
        "relational_projection": True if rich else "scalar_fields_only",
        "duality_view": bool(rich),
        "vector_columns": bool(vectors),
        "memory": True,
    }
    return MigrationProfile(
        mode=mode,
        document_count=count,
        sample_size=len(docs),
        source=source_config.get_source_dict(),
        fields=fields,
        vectors=vectors,
        strategy=strategy,
        warnings=warnings,
    )


def assess_dict(sample_size: int = 100) -> dict:
    return assess(sample_size=sample_size).to_dict()

data_migration_harness/source_config.py.content:
"""Runtime MongoDB source connection management.

The Developer Hub app starts with the .env Mongo source, but users can replace
it at runtime with another MongoDB URI/database/collection. The active source is
process-local by design: restarting the FastAPI app returns to .env defaults.
"""

from __future__ import annotations

import os
from dataclasses import asdict, dataclass
from threading import RLock
from typing import Any

from pymongo import MongoClient


@dataclass
class SourceConfig:
    kind: str = "mongodb"
    uri: str = "mongodb://localhost:27017"
    database: str = "reviews_demo"
    collection: str = "products"
    status: str = "connected"
    document_count: int | None = None
    error: str | None = None


_lock = RLock()
_source = SourceConfig(
    uri=os.environ.get("MONGO_URI", "mongodb://localhost:27017"),
    database=os.environ.get("MONGO_DB", "reviews_demo"),
    collection=os.environ.get("MONGO_COLLECTION", "products"),
)
_client: MongoClient | None = None


def _new_client(uri: str) -> MongoClient:
    return MongoClient(uri, serverSelectionTimeoutMS=5000)


def _ping_and_count(uri: str, database: str, collection_name: str) -> tuple[MongoClient, int]:
    client = _new_client(uri)
    client.admin.command("ping")
    db = client[database]
    if collection_name not in db.list_collection_names():
        raise ValueError(f"Collection '{database}.{collection_name}' does not exist")
    return client, db[collection_name].count_documents({})


def get_source() -> SourceConfig:
    with _lock:
        out = SourceConfig(**asdict(_source))
    if out.status == "connected":
        try:
            out.document_count = collection().count_documents({})
            out.error = None
        except Exception as e:
            out.status = "error"
            out.error = f"{type(e).__name__}: {str(e)[:200]}"
    return out


def get_source_dict() -> dict[str, Any]:
    return asdict(get_source())


def test_source(uri: str, database: str, collection_name: str) -> dict:
    try:
        client, count = _ping_and_count(uri, database, collection_name)
        col = client[database][collection_name]
        vector_count = col.count_documents(
            {
                "$or": [
                    {"review_embedding": {"$exists": True}},
                    {"embedding": {"$exists": True}},
                ]
            }
        )
        client.close()
        return {
            "ok": True,
            "kind": "mongodb",
            "uri": uri,
            "database": database,
            "collection": collection_name,
            "document_count": count,
            "vector_count_hint": vector_count,
        }
    except Exception as e:
        return {"ok": False, "error": f"{type(e).__name__}: {str(e)[:500]}"}


def set_source(uri: str, database: str, collection_name: str) -> SourceConfig:
    global _source, _client
    client, count = _ping_and_count(uri, database, collection_name)
    with _lock:
        if _client is not None:
            try:
                _client.close()
            except Exception:
                pass
        _client = client
        _source = SourceConfig(
            uri=uri,
            database=database,
            collection=collection_name,
            status="connected",
            document_count=count,
        )
    return get_source()


def disconnect_source() -> SourceConfig:
    global _source, _client
    with _lock:
        if _client is not None:
            try:
                _client.close()
            except Exception:
                pass
        _client = None
        _source = SourceConfig(
            uri=_source.uri,
            database=_source.database,
            collection=_source.collection,
            status="disconnected",
            document_count=None,
        )
    return get_source()


def client() -> MongoClient:
    global _client
    with _lock:
        if _source.status != "connected":
            raise RuntimeError("No MongoDB source is connected")
        if _client is None:
            _client = _new_client(_source.uri)
        return _client


def database():
    with _lock:
        db_name = _source.database
    return client()[db_name]


def collection():
    with _lock:
        name = _source.collection
    return database()[name]


def collection_name() -> str:
    with _lock:
        return _source.collection


def reset_to_env() -> SourceConfig:
    return set_source(
        os.environ.get("MONGO_URI", "mongodb://localhost:27017"),
        os.environ.get("MONGO_DB", "reviews_demo"),
        os.environ.get("MONGO_COLLECTION", "products"),
    )

data_migration_harness/tools/agent_tools.content:
"""Layer 3 agent tool surface.

The LLM sees four tools per side: vector_search, count_products, top_products,
group_by. Each has a Mongo implementation and an Oracle implementation.
The agent's experience of which tools exist is identical on both sides -- that's
the migration story Layer 3 tells when the substrate flips.

All tool functions take ``side`` as their first argument so the dispatch table
can route them without knowing which database is live. The LLM never sees
``side`` in the schema; it's injected by the agent loop in model.py.
"""

from __future__ import annotations

# ── Vector search ─────────────────────────────────────────────────────────────

_embedding_model = None


def _embed(text: str) -> list[float]:
    """Lazy-load the sentence-transformer embedding model (shared singleton)."""
    global _embedding_model
    if _embedding_model is None:
        import os

        from sentence_transformers import SentenceTransformer

        model_name = os.environ.get("EMBEDDING_MODEL", "sentence-transformers/all-MiniLM-L6-v2")
        _embedding_model = SentenceTransformer(model_name)
    return _embedding_model.encode([text], normalize_embeddings=True)[0].tolist()


def vector_search(side: str, query: str, k: int = 5) -> list[dict]:
    """Search reviews semantically. Use for 'what do people say' questions.

    Args:
        side: 'mongo' or 'oracle'.
        query: The natural-language question to embed and search for.
        k: Number of results to return (default 5).

    Returns:
        List of dicts with name, category, review_text, score keys.

    Example:
        >>> vector_search("mongo", "wireless headphones noise cancelling", k=3)
    """
    from data_migration_harness import source_config
    from data_migration_harness.tools import mongo_reader
    from data_migration_harness.tools.vector_oracle import vector_search_oracle

    qv = _embed(query)
    if side == "mongo":
        results = mongo_reader.vector_search_mongo(source_config.collection_name(), qv, k=k)
    else:
        results = vector_search_oracle(qv, k=k)
    return [
        {
            "name": r.get("name"),
            "category": r.get("category"),
            "review_text": r.get("review_text") or r.get("text", ""),
            "score": round(float(r.get("score", r.get("distance", 0))), 4),
        }
        for r in results
    ]


# ── Count ─────────────────────────────────────────────────────────────────────


def count_products(
    side: str,
    category: str | None = None,
    min_rating: int | None = None,
    verified_only: bool = False,
) -> dict:
    """Count products matching optional filters.

    Args:
        side: 'mongo' or 'oracle'.
        category: Optional category name filter (Audio, Wearables, Home, etc.).
        min_rating: Only count products with at least one review at or above this rating.
        verified_only: Restrict to products with verified-buyer reviews only.

    Returns:
        Dict with a single 'count' key.

    Example:
        >>> count_products("oracle", category="Audio", min_rating=4)
    """
    if side == "mongo":
        return _count_products_mongo(
            category=category, min_rating=min_rating, verified_only=verified_only
        )
    return _count_products_oracle(
        category=category, min_rating=min_rating, verified_only=verified_only
    )


def _count_products_mongo(
    category: str | None,
    min_rating: int | None,
    verified_only: bool,
) -> dict:
    from data_migration_harness import source_config

    match: dict = {}
    if category:
        match["category"] = category
    if min_rating is not None:
        review_filter: dict = {"rating": {"$gte": min_rating}}
        if verified_only:
            review_filter["verified_buyer"] = True
        match["reviews"] = {"$elemMatch": review_filter}
    elif verified_only:
        match["reviews"] = {"$elemMatch": {"verified_buyer": True}}
    pipeline = [{"$match": match}, {"$count": "n"}]
    result = list(source_config.collection().aggregate(pipeline))
    return {"count": result[0]["n"] if result else 0}


def _count_products_oracle(
    category: str | None,
    min_rating: int | None,
    verified_only: bool,
) -> dict:
    from data_migration_harness.environment import oracle_pool

    pool = oracle_pool()
    params: dict = {}
    clauses: list[str] = []

    if min_rating is not None or verified_only:
        # Need a join with reviews
        sql = "SELECT COUNT(DISTINCT p.product_id) FROM products p JOIN reviews r ON r.product_id = p.product_id"
        if category:
            clauses.append("p.category = :cat")
            params["cat"] = category
        if min_rating is not None:
            clauses.append("r.rating >= :min_rating")
            params["min_rating"] = min_rating
        if verified_only:
            clauses.append("r.verified_buyer = 1")
    else:
        sql = "SELECT COUNT(*) FROM products p"
        if category:
            clauses.append("p.category = :cat")
            params["cat"] = category

    if clauses:
        sql += " WHERE " + " AND ".join(clauses)

    with pool.acquire() as conn:
        cur = conn.cursor()
        cur.execute(sql, params)
        (n,) = cur.fetchone()
    return {"count": int(n)}


# ── Top products ──────────────────────────────────────────────────────────────


def top_products(
    side: str,
    by: str = "price",
    order: str = "desc",
    limit: int = 5,
    max_price: float | None = None,
) -> list[dict]:
    """Get top-N products by price or average rating.

    Args:
        side: 'mongo' or 'oracle'.
        by: 'price' or 'rating' -- the field to rank by.
        order: 'desc' (highest first) or 'asc' (lowest first).
        limit: Number of results to return (default 5).
        max_price: Optional upper price ceiling.

    Returns:
        List of dicts with name, category, price, avg_rating keys.

    Example:
        >>> top_products("oracle", by="rating", order="desc", limit=3)
    """
    if side == "mongo":
        return _top_products_mongo(by=by, order=order, limit=limit, max_price=max_price)
    return _top_products_oracle(by=by, order=order, limit=limit, max_price=max_price)


def _top_products_mongo(
    by: str,
    order: str,
    limit: int,
    max_price: float | None,
) -> list[dict]:
    from data_migration_harness import source_config

    sort_dir = -1 if order == "desc" else 1

    match_stage: dict = {}
    if max_price is not None:
        match_stage["price"] = {"$lte": max_price}

    if by == "price":
        pipeline: list = []
        if match_stage:
            pipeline.append({"$match": match_stage})
        pipeline += [
            {"$sort": {"price": sort_dir}},
            {"$limit": limit},
            {
                "$project": {
                    "_id": 0,
                    "name": 1,
                    "category": 1,
                    "price": 1,
                    "avg_rating": {"$avg": "$reviews.rating"},
                }
            },
        ]
    else:
        # Sort by computed average rating
        pipeline = []
        if match_stage:
            pipeline.append({"$match": match_stage})
        pipeline += [
            {"$addFields": {"avg_rating": {"$avg": "$reviews.rating"}}},
            {"$sort": {"avg_rating": sort_dir}},
            {"$limit": limit},
            {"$project": {"_id": 0, "name": 1, "category": 1, "price": 1, "avg_rating": 1}},
        ]

    results = list(source_config.collection().aggregate(pipeline))
    return [
        {
            "name": r.get("name"),
            "category": r.get("category"),
            "price": r.get("price"),
            "avg_rating": round(float(r["avg_rating"]), 2)
            if r.get("avg_rating") is not None
            else None,
        }
        for r in results
    ]


def _top_products_oracle(
    by: str,
    order: str,
    limit: int,
    max_price: float | None,
) -> list[dict]:
    from data_migration_harness.environment import oracle_pool

    pool = oracle_pool()
    params: dict = {"lim": limit}
    where_clauses: list[str] = []

    if max_price is not None:
        where_clauses.append("p.price <= :max_price")
        params["max_price"] = max_price

    where_sql = ("WHERE " + " AND ".join(where_clauses)) if where_clauses else ""
    order_dir = "DESC" if order == "desc" else "ASC"

    if by == "price":
        sort_col = "p.price"
    else:
        sort_col = "avg_rating"

    sql = f"""
        SELECT p.name, p.category, p.price,
               ROUND(AVG(r.rating), 2) AS avg_rating
        FROM products p
        LEFT JOIN reviews r ON r.product_id = p.product_id
        {where_sql}
        GROUP BY p.product_id, p.name, p.category, p.price
        ORDER BY {sort_col} {order_dir} NULLS LAST
        FETCH FIRST :lim ROWS ONLY
    """
    with pool.acquire() as conn:
        cur = conn.cursor()
        cur.execute(sql, params)
        cols = [c[0].lower() for c in cur.description]
        return [dict(zip(cols, row, strict=False)) for row in cur.fetchall()]


# ── Group by ──────────────────────────────────────────────────────────────────


def group_by(
    side: str,
    group_field: str = "category",
    metric_field: str = "rating",
    agg: str = "avg",
) -> dict:
    """Group products by a field and compute an aggregate over a metric.

    When group_field='category', metric_field='rating', and agg='avg', the
    response sets is_chart=True so the orchestrator emits a bar chart to the
    frontend rather than embedding the data in the text response.

    Args:
        side: 'mongo' or 'oracle'.
        group_field: 'category' or 'vendor' -- the field to group by.
        metric_field: 'rating', 'price', or 'review_count' -- the metric to aggregate.
        agg: 'avg', 'sum', 'count', 'max', or 'min'.

    Returns:
        Dict with is_chart (bool) and rows (list of {group, value, count}).

    Example:
        >>> group_by("oracle", group_field="category", metric_field="rating", agg="avg")
    """
    if side == "mongo":
        rows = _group_by_mongo(group_field=group_field, metric_field=metric_field, agg=agg)
    else:
        rows = _group_by_oracle(group_field=group_field, metric_field=metric_field, agg=agg)

    is_chart = group_field == "category" and metric_field == "rating" and agg == "avg"
    return {"is_chart": is_chart, "rows": rows}


def _group_by_mongo(group_field: str, metric_field: str, agg: str) -> list[dict]:
    from data_migration_harness import source_config

    # Resolve the grouping key path in the Mongo document
    if group_field == "vendor":
        group_id_expr = "$vendor.name"
    else:
        group_id_expr = f"${group_field}"

    # Resolve the metric accumulator
    agg_ops = {"avg": "$avg", "sum": "$sum", "count": "$sum", "max": "$max", "min": "$min"}
    agg_op = agg_ops.get(agg, "$avg")

    if metric_field == "review_count":
        # Count of review sub-documents per product, then sum/avg across groups
        pass
    elif metric_field == "rating":
        # Reviews are embedded: unwind first, then aggregate rating
        pass
    else:
        pass

    if metric_field in ("rating", "review_count"):
        pipeline = [
            {"$unwind": "$reviews"},
            {
                "$group": {
                    "_id": group_id_expr,
                    "value": (
                        {"$sum": 1}
                        if metric_field == "review_count" and agg in ("count", "sum")
                        else {agg_op: "$reviews.rating"}
                    ),
                    "count": {"$sum": 1},
                }
            },
            {"$sort": {"value": -1}},
            {"$project": {"_id": 0, "group": "$_id", "value": 1, "count": 1}},
        ]
    else:
        pipeline = [
            {
                "$group": {
                    "_id": group_id_expr,
                    "value": {agg_op: f"${metric_field}"},
                    "count": {"$sum": 1},
                }
            },
            {"$sort": {"value": -1}},
            {"$project": {"_id": 0, "group": "$_id", "value": 1, "count": 1}},
        ]

    results = list(source_config.collection().aggregate(pipeline))
    return [
        {
            "group": r.get("group", "Unknown"),
            "value": round(float(r["value"]), 2) if r.get("value") is not None else 0,
            "count": int(r.get("count", 0)),
        }
        for r in results
    ]


def _group_by_oracle(group_field: str, metric_field: str, agg: str) -> list[dict]:
    from data_migration_harness.environment import oracle_pool

    pool = oracle_pool()

    agg_sql = agg.upper()
    # Map group_field to the SQL column name
    group_col = "p.vendor_name" if group_field == "vendor" else "p.category"

    if metric_field == "review_count":
        metric_expr = "COUNT(r.review_id)"
        join_type = "LEFT JOIN"
    elif metric_field == "rating":
        metric_expr = f"ROUND({agg_sql}(r.rating), 2)"
        join_type = "LEFT JOIN"
    else:
        # price: no join needed
        metric_expr = f"ROUND({agg_sql}(p.price), 2)"
        join_type = "LEFT JOIN"

    sql = f"""
        SELECT {group_col} AS grp,
               {metric_expr} AS val,
               COUNT(DISTINCT p.product_id) AS cnt
        FROM products p
        {join_type} reviews r ON r.product_id = p.product_id
        GROUP BY {group_col}
        ORDER BY val DESC NULLS LAST
    """
    with pool.acquire() as conn:
        cur = conn.cursor()
        cur.execute(sql)
        return [
            {
                "group": row[0] or "Unknown",
                "value": round(float(row[1]), 2) if row[1] is not None else 0,
                "count": int(row[2]),
            }
            for row in cur.fetchall()
        ]


# ── Tool registry ─────────────────────────────────────────────────────────────

TOOL_REGISTRY: dict[str, object] = {
    "vector_search": vector_search,
    "count_products": count_products,
    "top_products": top_products,
    "group_by": group_by,
}

# ── JSON Schema for the LLM ───────────────────────────────────────────────────

TOOL_SCHEMAS = [
    {
        "type": "FUNCTION",
        "function": {
            "name": "vector_search",
            "description": (
                "Search the product reviews for reviews semantically similar to the query. "
                "Use for open-ended questions like 'what do people say about X' or "
                "'tell me about Y' or 'what are customers saying'."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {
                        "type": "string",
                        "description": "The semantic question to search for in the reviews",
                    },
                    "k": {
                        "type": "integer",
                        "description": "Number of results to return (default 5)",
                    },
                },
                "required": ["query"],
            },
        },
    },
    {
        "type": "FUNCTION",
        "function": {
            "name": "count_products",
            "description": (
                "Count products in the database, optionally filtered by category, "
                "minimum rating, or verified-buyer reviews. "
                "Use for 'how many products', 'how many items', 'how many reviews' questions."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "category": {
                        "type": "string",
                        "description": "Filter by category: Audio, Wearables, Home, Kitchen, Outdoor, or Office",
                    },
                    "min_rating": {
                        "type": "integer",
                        "description": "Only count products with at least one review at or above this star rating (1-5)",
                    },
                    "verified_only": {
                        "type": "boolean",
                        "description": "Only count products that have verified-buyer reviews",
                    },
                },
            },
        },
    },
    {
        "type": "FUNCTION",
        "function": {
            "name": "top_products",
            "description": (
                "List products ranked by price or average rating. "
